def extract_receipt_text(receipt):
    # Extracting the menu items from the receipt
    menu_items = []
    for line in receipt.split("\n"):
        if "items:" in line:
            items = line.split("items:")
            menu_items.extend([item.strip() for item in items[1].split(",")])

    # Extracting the quantity, unit price, and item price from each menu item
    menu_data = []
    for item in menu_items:
        item_data = item.split(":")
        menu_data.append({
            "nm": item_data[0],
            "cnt": item_data[1],
            "unitprice": item_data[2],
            "price": item_data[3]
        })

    # Calculating the subtotal, discount, tax, service, and total
    subtotal = sum([float(item["price"]) * float(item["cnt"]) for item in menu_data])
    discount = subtotal * 0.05
    tax = subtotal * 0.07
    service = subtotal * 0.01
    total = subtotal - discount - tax + service

    # Formatting the data into a JSON object
    json_data = {
        "menu": menu_data,
        "sub_total": {
            "subtotal_price": f"{subtotal:.2f}",
            "discount_price": f"{discount:.2f}",
            "tax_price": f"{tax:.2f}",
            "service_price": f"{service:.2f}"
        },
        "total": {
            "total_price": f"{total:.2f}",
            "cashprice": f"{subtotal:.2f}",
            "changeprice": f"{total - subtotal:.2f}",
            "creditcardprice": f"{total:.2f}"
        }
    }

    return json_data

